unit lipdecide;

{$mode objfpc}{$H+}

interface

uses
  globals, Math;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

const
  NUM_LIC = 15;

function Pow10Int(E: integer): real;
var
  I: integer;
begin
  Result := 1.0;
  if E > 0 then
    for I := 1 to E do
      Result := Result * 10.0
  else if E < 0 then
    for I := 1 to -E do
      Result := Result / 10.0;
end;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  MaxAbs, Scale, Tol: real;
  E: integer;
begin
  MaxAbs := Abs(A);
  if Abs(B) > MaxAbs then
    MaxAbs := Abs(B);

  if MaxAbs = 0.0 then
    Exit(EQ);

  E := 0;
  Scale := MaxAbs;
  while Scale >= 10.0 do
  begin
    Scale := Scale / 10.0;
    Inc(E);
  end;
  while Scale < 1.0 do
  begin
    Scale := Scale * 10.0;
    Dec(E);
  end;

  Tol := 0.5 * Pow10Int(E - 5);

  if Abs(A - B) <= Tol then
    Result := EQ
  else if A < B then
    Result := LT
  else
    Result := GT;
end;

function SamePoint(I, J: integer): boolean;
begin
  Result := (REALCOMPARE(X[I], X[J]) = EQ) and
            (REALCOMPARE(Y[I], Y[J]) = EQ);
end;

function Dist2(I, J: integer): real;
var
  DX, DY: real;
begin
  DX := X[J] - X[I];
  DY := Y[J] - Y[I];
  Result := DX * DX + DY * DY;
end;

function TriangleArea(I, J, K: integer): real;
var
  Cross: real;
begin
  Cross := (X[J] - X[I]) * (Y[K] - Y[I]) -
           (Y[J] - Y[I]) * (X[K] - X[I]);
  Result := Abs(Cross) * 0.5;
end;

function PointQuadrant(I: integer): integer;
begin
  if REALCOMPARE(X[I], 0.0) = GT then
  begin
    if REALCOMPARE(Y[I], 0.0) = LT then
      Result := 4
    else
      Result := 1;
  end
  else if REALCOMPARE(X[I], 0.0) = EQ then
  begin
    if REALCOMPARE(Y[I], 0.0) = LT then
      Result := 3
    else
      Result := 1;
  end
  else
  begin
    if REALCOMPARE(Y[I], 0.0) = LT then
      Result := 3
    else
      Result := 2;
  end;
end;

function AngleCondition(I, J, K: integer): boolean;
var
  Ux, Uy, Vx, Vy, Denom, Dot, Threshold: real;
begin
  if SamePoint(I, J) or SamePoint(K, J) then
    Exit(False);

  Ux := X[I] - X[J];
  Uy := Y[I] - Y[J];
  Vx := X[K] - X[J];
  Vy := Y[K] - Y[J];

  Denom := Sqrt((Ux * Ux + Uy * Uy) * (Vx * Vx + Vy * Vy));
  if Denom = 0.0 then
    Exit(False);

  Dot := Ux * Vx + Uy * Vy;
  Threshold := -Denom * Cos(PARAMETERS.EPSILON);
  Result := REALCOMPARE(Dot, Threshold) = GT;
end;

function TriangleFitsRadius(I, J, K: integer; R: real): boolean;
var
  D1, D2, D3, A, B, C, Cross, A2, R2, Max2, Sum2: real;
begin
  D1 := Dist2(I, J);
  D2 := Dist2(I, K);
  D3 := Dist2(J, K);

  A := D1;
  B := D2;
  C := D3;
  if REALCOMPARE(A, B) = LT then
  begin
    D1 := A; A := B; B := D1;
  end;
  if REALCOMPARE(A, C) = LT then
  begin
    D1 := A; A := C; C := D1;
  end;
  if REALCOMPARE(B, C) = LT then
  begin
    D1 := B; B := C; C := D1;
  end;

  Max2 := A;
  Sum2 := B + C;
  R2 := R * R;

  if REALCOMPARE(Max2, Sum2) <> LT then
  begin
    Result := REALCOMPARE(Max2, 4.0 * R2) = GT;
    Exit;
  end;

  Cross := (X[J] - X[I]) * (Y[K] - Y[I]) -
           (Y[J] - Y[I]) * (X[K] - X[I]);
  A2 := Cross * Cross;

  Result := REALCOMPARE(A * B * C, 4.0 * A2 * R2) = GT;
end;

function PointFartherThanDistance(I, J, K: integer; Dist: real): boolean;
var
  Dx, Dy, Cross, Line2, Dist2Limit: real;
begin
  Dx := X[J] - X[I];
  Dy := Y[J] - Y[I];
  Line2 := Dx * Dx + Dy * Dy;
  Dist2Limit := Dist * Dist;

  if SamePoint(I, J) then
  begin
    Result := REALCOMPARE(Dist2(I, K), Dist2Limit) = GT;
    Exit;
  end;

  Cross := Dx * (Y[K] - Y[I]) - Dy * (X[K] - X[I]);
  Result := REALCOMPARE(Cross * Cross, Dist2Limit * Line2) = GT;
end;

function LIC1Met: boolean;
var
  I: integer;
  Limit2: real;
begin
  Result := False;
  Limit2 := PARAMETERS.LENGTH1 * PARAMETERS.LENGTH1;
  for I := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(Dist2(I, I + 1), Limit2) = GT then
      Exit(True);
end;

function LIC2Met: boolean;
var
  I: integer;
begin
  Result := False;
  if NUMPOINTS < 3 then
    Exit;
  for I := 1 to NUMPOINTS - 2 do
    if not TriangleFitsRadius(I, I + 1, I + 2, PARAMETERS.RADIUS1) then
      Exit(True);
end;

function LIC3Met: boolean;
var
  I: integer;
begin
  Result := False;
  for I := 1 to NUMPOINTS - 2 do
    if AngleCondition(I, I + 1, I + 2) then
      Exit(True);
end;

function LIC4Met: boolean;
var
  I: integer;
begin
  Result := False;
  for I := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(TriangleArea(I, I + 1, I + 2), PARAMETERS.AREA1) = GT then
      Exit(True);
end;

function LIC5Met: boolean;
var
  Start, I, Q, Count: integer;
  Seen: array[1..4] of boolean;
begin
  Result := False;
  if PARAMETERS.Q_PTS > NUMPOINTS then
    Exit;

  for Start := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    Seen[1] := False;
    Seen[2] := False;
    Seen[3] := False;
    Seen[4] := False;
    Count := 0;
    for I := Start to Start + PARAMETERS.Q_PTS - 1 do
    begin
      Q := PointQuadrant(I);
      if not Seen[Q] then
      begin
        Seen[Q] := True;
        Inc(Count);
      end;
    end;
    if Count > PARAMETERS.QUADS then
      Exit(True);
  end;
end;

function LIC6Met: boolean;
var
  I: integer;
begin
  Result := False;
  for I := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[I + 1], X[I]) = LT then
      Exit(True);
end;

function LIC7Met: boolean;
var
  Start, K: integer;
begin
  Result := False;
  if NUMPOINTS < 3 then
    Exit;

  for Start := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    if SamePoint(Start, Start + PARAMETERS.N_PTS - 1) then
    begin
      for K := Start + 1 to Start + PARAMETERS.N_PTS - 2 do
        if REALCOMPARE(Dist2(Start, K), PARAMETERS.DIST * PARAMETERS.DIST) = GT then
          Exit(True);
    end
    else
    begin
      for K := Start + 1 to Start + PARAMETERS.N_PTS - 2 do
        if PointFartherThanDistance(Start, Start + PARAMETERS.N_PTS - 1, K,
                                    PARAMETERS.DIST) then
          Exit(True);
    end;
  end;
end;

function LIC8Met: boolean;
var
  I: integer;
  Limit2: real;
begin
  Result := False;
  if NUMPOINTS < 3 then
    Exit;

  Limit2 := PARAMETERS.LENGTH1 * PARAMETERS.LENGTH1;
  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    if REALCOMPARE(Dist2(I, I + PARAMETERS.K_PTS + 1), Limit2) = GT then
      Exit(True);
end;

function LIC9Met: boolean;
var
  I: integer;
begin
  Result := False;
  if NUMPOINTS < 5 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    if not TriangleFitsRadius(I,
                              I + PARAMETERS.A_PTS + 1,
                              I + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2,
                              PARAMETERS.RADIUS1) then
      Exit(True);
end;

function LIC10Met: boolean;
var
  I: integer;
begin
  Result := False;
  if NUMPOINTS < 5 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    if AngleCondition(I,
                      I + PARAMETERS.C_PTS + 1,
                      I + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2) then
      Exit(True);
end;

function LIC11Met: boolean;
var
  I: integer;
begin
  Result := False;
  if NUMPOINTS < 5 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    if REALCOMPARE(TriangleArea(I,
                                I + PARAMETERS.E_PTS + 1,
                                I + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2),
                   PARAMETERS.AREA1) = GT then
      Exit(True);
end;

function LIC12Met: boolean;
var
  I: integer;
begin
  Result := False;
  if NUMPOINTS < 3 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    if REALCOMPARE(X[I + PARAMETERS.G_PTS + 1], X[I]) = LT then
      Exit(True);
end;

function LIC13Met: boolean;
var
  I: integer;
  Limit1, Limit2, D2Val: real;
  FoundGreater, FoundLess: boolean;
begin
  Result := False;
  if NUMPOINTS < 3 then
    Exit;

  Limit1 := PARAMETERS.LENGTH1 * PARAMETERS.LENGTH1;
  Limit2 := PARAMETERS.LENGTH2 * PARAMETERS.LENGTH2;
  FoundGreater := False;
  FoundLess := False;

  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    D2Val := Dist2(I, I + PARAMETERS.K_PTS + 1);
    if REALCOMPARE(D2Val, Limit1) = GT then
      FoundGreater := True;
    if REALCOMPARE(D2Val, Limit2) = LT then
      FoundLess := True;
    if FoundGreater and FoundLess then
      Exit(True);
  end;
end;

function LIC14Met: boolean;
var
  I: integer;
  FoundOutside, FoundInside: boolean;
begin
  Result := False;
  if NUMPOINTS < 5 then
    Exit;

  FoundOutside := False;
  FoundInside := False;

  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if not TriangleFitsRadius(I,
                              I + PARAMETERS.A_PTS + 1,
                              I + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2,
                              PARAMETERS.RADIUS1) then
      FoundOutside := True;
    if TriangleFitsRadius(I,
                          I + PARAMETERS.A_PTS + 1,
                          I + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2,
                          PARAMETERS.RADIUS2) then
      FoundInside := True;
    if FoundOutside and FoundInside then
      Exit(True);
  end;
end;

function LIC15Met: boolean;
var
  I: integer;
  FoundGreater, FoundLess: boolean;
  Area: real;
begin
  Result := False;
  if NUMPOINTS < 5 then
    Exit;

  FoundGreater := False;
  FoundLess := False;
  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    Area := TriangleArea(I,
                         I + PARAMETERS.E_PTS + 1,
                         I + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2);
    if REALCOMPARE(Area, PARAMETERS.AREA1) = GT then
      FoundGreater := True;
    if REALCOMPARE(Area, PARAMETERS.AREA2) = LT then
      FoundLess := True;
    if FoundGreater and FoundLess then
      Exit(True);
  end;
end;

procedure DECIDE;
var
  I, J: integer;
  RowAllTrue: boolean;
begin
  CMV[1] := LIC1Met;
  CMV[2] := LIC2Met;
  CMV[3] := LIC3Met;
  CMV[4] := LIC4Met;
  CMV[5] := LIC5Met;
  CMV[6] := LIC6Met;
  CMV[7] := LIC7Met;
  CMV[8] := LIC8Met;
  CMV[9] := LIC9Met;
  CMV[10] := LIC10Met;
  CMV[11] := LIC11Met;
  CMV[12] := LIC12Met;
  CMV[13] := LIC13Met;
  CMV[14] := LIC14Met;
  CMV[15] := LIC15Met;

  for I := 1 to NUM_LIC do
    for J := 1 to NUM_LIC do
      if I <> J then
        case LCM[I, J] of
          NOTUSED: PUM[I, J] := True;
          ANDD:    PUM[I, J] := CMV[I] and CMV[J];
          ORR:     PUM[I, J] := CMV[I] or CMV[J];
        end;

  for I := 1 to NUM_LIC do
  begin
    if not PUM[I, I] then
    begin
      FUV[I] := True;
      Continue;
    end;

    RowAllTrue := True;
    for J := 1 to NUM_LIC do
      if not PUM[I, J] then
      begin
        RowAllTrue := False;
        Break;
      end;
    FUV[I] := RowAllTrue;
  end;

  LAUNCH := True;
  for I := 1 to NUM_LIC do
    if not FUV[I] then
    begin
      LAUNCH := False;
      Break;
    end;
end;

end.
